sp_widget.client_script:
function ($scope, $rootScope, amb, $timeout, $log, spUtil) {
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: FIELDS
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
//------------------------------------------------------------------------------------------------------------------------			
	var c = this;
	// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
	var watcher;
	initRecordWatcher(c.data.table, "sys_id=" + c.data.sys_id);
	function initRecordWatcher(table, filter) {
		if (watcher)
			watcher.unsubscribe();

		if (table && filter) {
			// STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
			var params = {};
			var watcherChannel = amb.getChannelRW(table, filter);
			amb.connect();
			watcher = watcherChannel.subscribe(function(name) {
				// STRY0154672
				var reloadForm = checkChangedFields(name.data);
				if(reloadForm){
					$scope.server.update();
				}
			});
		}
	}

	// STRY0154672
	function checkChangedFields(data) {
		var changes = data.changes;
		var checkChanges = false;
		// NOTE: this can be used in the future to stop post back all together 
		if(c.data && c.data.fields){
			c.data.fields.filter(function(field){
				if(changes.includes(field.name)){
					checkChanges=true;
				}
			});
		}
		return checkChanges;		
	}

	// STRY0113839
	$scope.openParent = function() {
			var url = c.data.url_Properties.portal_url_ref +
					'?id=' +  c.data.url_Properties.pageId + 
					'&table=' + c.data.url_Properties.pageTable +
					'&sys_id=' + c.data.parent_sys_id +
					'&view=' + c.data.url_Properties.view;
		window.open(url);

	}

	var onListClick = $rootScope.$on('$sp.list.click', function(e, parms) {
		// if the event was not raised on the table associated with this widget, ignore the click
		if(c.data.table == parms.table && c.data.sys_id != parms.sys_id){
			c.data.sys_id = parms.sys_id;
			refreshWidget();
		}
	});
	// because of the record watcher above, this scope click event might reload the data 2 times instead of 1
	//var onSaveUpdate = $scope.$on('sp.form.record.updated', refreshWidget);
	// STRY0093948 - the tasker form with tab is rasing this as a rootscope broadcast, updated to catch
	$rootScope.$on('$taskerTabbedForm.drillDownList.click', function(e, parms) {
		// if the event was not raised on the table associated with this widget, ignore the click
		if(c.data.table == parms.table && c.data.sys_id != parms.sys_id){
			c.data.sys_id = parms.sys_id;
			refreshWidget();
		}
	});
	$rootScope.$on('$TaskerTaskList.click', function(e, parms) {
		// if the item is already selected ignore the click
		if(c.data.sys_id != parms.sys_id){
			c.data.sys_id = parms.sys_id;
			refreshWidget();
		}
	});			

	function refreshWidget() { 
		$scope.server.update().then(function(){
			// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
			initRecordWatcher(c.data.table, "sys_id=" + c.data.sys_id);
		});
	}
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
// WIDGET BASE: FIELDS
// 2.7.0 | 2021-11-16 | raj  | STRY0113838 - Tasker Settings- Allow for custom "URL Suffix" for Tasker Portal
//                                         Changes made in Server and Client Script
// 2.8.5 | 2024-09-29 | raj | STRY0154672 - Performance Improvements
//                                          Client Script Only, updated recordwatcher handling
//
//------------------------------------------------------------------------------------------------------------------------
(function(data, options) {
    //2.5.21: 08.26.20 | DTLV | KT | Set up Title
		if (options.show_systemfields == null)
			data.show_systemfields = true;
		else data.show_systemfields = options.show_systemfields;

    data.pickupMsg = gs.getMessage(options.pickup_msg);

    // DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
		var gr;
		if(input){
			data.table = input.table;
			data.sys_id = input.sys_id;
			gr = new GlideRecordSecure(data.table);
			if(!gr.get(data.sys_id)){
				return;
			}
		} else {
			gr = $sp.getRecord();
			if (gr == null)
				return;
		}

		// STRY0113838
		var oUserPref = new tasker_User_Form_Preferences();
		data.url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(data.sys_id,'sp');


    data.canRead = gr.canRead();
    if (!data.canRead)
        return;

    var agent = "";
    var a = $sp.getField(gr, 'assigned_to');
    if (a != null)
        agent = a.display_value;

    // KT - TLV - STRY0057360 - Macro Widget
    var fields;
    data.dynamic_tree = $sp.getParameter("dynamic_tree");
    if (data.dynamic_tree == 'true') {
        data.filter = options.filter;
        fields = $sp.getFields(gr, data.filter);
    } else {
        fields = $sp.getFields(gr, 'comments,parent,u_task_tree,suggested_task,state,assigned_to,u_reviewer,suspense_date,tasker_type');
				// STRY0089251 - this is a special case as we want to change the label and always show true
				var reviewRequiredFieldToUse = {};
				var reviewRequired = $sp.getField(gr, 'provide_response');
				if (reviewRequired.display_value == 'true'){
					reviewRequiredFieldToUse.label = reviewRequired.label;
					reviewRequiredFieldToUse.type = reviewRequired.type;
					reviewRequiredFieldToUse.value = reviewRequired.value;
					reviewRequiredFieldToUse.display_value = reviewRequired.display_value;
				}else{
					reviewRequiredFieldToUse.label = gs.getMessage('Tasker - Label Review Optional');
					reviewRequiredFieldToUse.value = 1;
					reviewRequiredFieldToUse.display_value = 'true';
					reviewRequiredFieldToUse.type = "boolean";
				}
				fields.push(reviewRequiredFieldToUse);

				fields.push($sp.getField(gr, 'primary_assignee'));
				fields.push($sp.getField(gr, 'status'));
				fields.push($sp.getField(gr, 'status_reason'));
				fields.push($sp.getField(gr, 'progress_of_sub_tasks'));
				fields.push($sp.getField(gr, 'u_parent_template'));
				fields.push($sp.getField(gr, 'decision'));
				fields.push($sp.getField(gr, 'on_behalf_of'));
				fields.push($sp.getField(gr, 'u_task_requester'));

    }

    // KT - TLV - STRY0057360 - Macro Widget: Add new condition
    if ($sp.getParameter("table") == "x_153465_discovert_route_task_instance" && data.dynamic_tree != 'true') {
        if (gr.getValue('parent') != null) {

            var grParent = new GlideRecordSecure(($sp.getParameter("table")));
            if (grParent.get(gr.getValue('parent'))) {
                if (grParent.assigned_to != null) {
                    data.parent_assigned_to = grParent.getDisplayValue('assigned_to');
                }
            }
        }

        if (gr.getValue('state') == '3') {
            fields.push($sp.getField(gr, 'u_completed_on_time'));
        }
        if (gr.getValue('u_clarification_requested') == '1') {
            fields.push($sp.getField(gr, 'u_clarification_requested'));
        }
        if (gr.getValue('extension_requested') == '1') {
            fields.push($sp.getField(gr, 'extension_requested'));
        }
        if (gr.getValue('reassignment_requested') == '1') {
            fields.push($sp.getField(gr, 'reassignment_requested'));
        }
        // KT - STRY0061096	
        var tDS = new taskerDocumentScripts();
        var currentAttachDocSettings = tDS.getAttachmentAndDocumentSettings(gr);

        var sharedA = $sp.getField(gr, 'u_shared_attachments');
        if (currentAttachDocSettings.sNOWAttachmentsOn == true) {
            sharedA.display_value = currentAttachDocSettings.sharingAttachments.toString();
            if (sharedA.display_value == "true")
                fields.push(sharedA);
        }

        var sharedD = $sp.getField(gr, 'u_shared_documents');
        if (currentAttachDocSettings.docIntDocumentsOn == true) {
            sharedD.display_value = currentAttachDocSettings.sharingDocuments.toString();
            if (sharedD.display_value == "true")
                fields.push(sharedD);
        }

        fields.push($sp.getField(gr, 'originator'));
    } /* else {

    }*/

    if (data.show_systemfields) {
				fields.push($sp.getField(gr, 'sys_created_by'));
        fields.push($sp.getField(gr, 'sys_created_on'));
        fields.push($sp.getField(gr, 'sys_updated_by'));
        fields.push($sp.getField(gr, 'sys_updated_on'));
    }



    if ($sp.getParameter("table") == "x_153465_discovert_route_task_instance") {
        //2.5.21: 08.26.20 | DTLV | KT | Set up Title
        data.only_specified_fields = false || options.only_specified_fields;
        data.title = options.title || gs.getMessage("Summary Card");// + gr.getValue('task_name');
        data.parent_sys_id = gr.getValue('parent');
    } else {
        data.title = gr.getLabel();
    }

    data.tableLabel = gr.getLabel();
    data.fields = fields;
    data.variables = $sp.getVariablesArray();
    data.agent = agent;
    data.agentPossible = gr.isValidField("assigned_to");
    data.table = gr.getTableName();
    data.sys_id = gr.getUniqueValue();

    //------------------------------------------------------ KTorres
    //var currentUser = gs.getUser().getID(); 
    //---------------------------------------------------------
})(data, options)
